public JavaWriter emitJavadoc(String javadoc, Object... params) throws IOException {
  String formatted = String.format(javadoc, params);

  indent();
  out.write("/**\n");
  for (String line : formatted.split("\n")) {
    indent();
    out.write(" *");
    if (!line.isEmpty()) {
      out.write(" ");
      out.write(line);
    }
    out.write("\n");
  }
  indent();
  out.write(" */\n");
  return this;
}

